'use client';

import { useState, useEffect } from 'react';
import Navbar from '../../../components/Navbar';
import Link from 'next/link';

export default function AttackSimulation() {
    const [loading, setLoading] = useState(true);
    const [scenarios, setScenarios] = useState<any[]>([]);

    useEffect(() => {
        const timer = setTimeout(() => {
            setScenarios([
                {
                    id: 1,
                    title: "AI-Native konkurrent: Nollmarginal-modellen",
                    description: "En ny aktör utnyttjar LLM-baserad automatisering för att hantera sälj och rådgivning till en bråkdel av era kostnader. De kan expandera globalt utan linjär personalökning.",
                    impact: "Ditt företag riskerar 30% priserosion på core-tjänster inom 24 månader.",
                    priority: "Kritisk"
                },
                {
                    id: 2,
                    title: "Automatiserad Värdekedja",
                    description: "En konkurrent bygger en vertikal AI-integration som tar bort behovet av era nuvarande mellanled. Deras time-to-market minskar från månader till dagar.",
                    impact: "Ert nuvarande lager- eller logistikvärde minskar drastiskt i betydelse.",
                    priority: "Strategisk"
                }
            ]);
            setLoading(false);
        }, 2500);
        return () => clearTimeout(timer);
    }, []);

    return (
        <div className="bg-soft min-h-100 flex flex-col">
            <Navbar />
            <div className="container py-20">
                <div className="flex justify-between items-end mb-16 accent-border-left">
                    <div>
                        <Link href="/dashboard" className="uppercase-spaced mb-2 block" style={{ color: 'var(--accent-teal)', fontSize: '0.65rem' }}>← Tillbaka till översikt</Link>
                        <h1 className="serif-font text-5xl">AI Attack Simulation</h1>
                        <p className="text-muted mt-2">Djuppanalys av hyper-effektiva utmanare.</p>
                    </div>
                    <button className="btn-primary" style={{ padding: '0.8rem 1.5rem', fontSize: '0.7rem' }} onClick={() => window.location.reload()}>Omgenerera Scenarier</button>
                </div>

                {loading ? (
                    <div className="card text-center py-32 flex flex-col items-center">
                        <div className="loader mb-8"></div>
                        <p className="serif-font text-xl">Analyserar branschdynamik och teknologiska språng...</p>
                    </div>
                ) : (
                    <div className="grid col-2 gap-12">
                        {scenarios.map((s) => (
                            <div key={s.id} className="card scenario-card bg-white">
                                <div className="flex justify-between items-center mb-10">
                                    <div className={`priority-pill uppercase-spaced ${s.priority === 'Kritisk' ? 'bg-red' : 'bg-gold'}`} style={{ fontSize: '0.6rem', color: 'white', padding: '4px 10px' }}>
                                        {s.priority}
                                    </div>
                                </div>
                                <h3 className="serif-font text-3xl mb-6">{s.title}</h3>
                                <p className="description mb-10" style={{ color: '#555', lineHeight: '1.8' }}>{s.description}</p>

                                <div className="impact-box p-8 bg-soft border">
                                    <h4 className="uppercase-spaced text-xs mb-4" style={{ color: 'var(--primary-navy)' }}>Strategisk Effekt</h4>
                                    <p className="text-sm font-bold">{s.impact}</p>
                                </div>

                                <button className="btn-primary w-full mt-10" style={{ fontSize: '0.7rem' }}>Visa Försvarsstrategi</button>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            <style jsx>{`
        .bg-soft { background: #fafafa; min-height: 100vh; }
        .grid { display: grid; grid-template-columns: 1fr 1fr; }
        .bg-red { background: #002B49; } /* Replaced red with navy for Olafsson feel */
        .bg-gold { background: var(--accent-teal); }
        .loader { width: 40px; height: 40px; border: 2px solid #eee; border-top-color: var(--primary-navy); border-radius: 50%; animation: spin 1s linear infinite; }
        @keyframes spin { to { transform: rotate(360deg); } }
        @media (max-width: 900px) { .grid { grid-template-columns: 1fr; } }
      `}</style>
        </div>
    );
}
